@pytest.mark.asyncio
async def test_cookies_per_domain() -> None:
    """Isolates cookies per domain during crawl."""
    engine_config = CrawlConfig(
        cookies_enabled=True, max_depth=1, respect_robots_txt=False
    )
    engine = create_engine(engine_config)
    url = os.environ["MOCK_SERVER_URL"] + "/fixtures/cookies_per_domain"

    result = await scrape(engine, url)
    assert len(result.cookies) == 1  # noqa: S101
    assert "domain_cookie" in result.cookies  # noqa: S101


